3	import (
4		"context"
5		"crypto/sha256"
6		"database/sql"
7		"encoding/hex"
8		"errors"
9		"fmt"
10		"sort"
11		"strings"
12		"time"
13	)
14	
15	const schemaMigrationsTable = "schema_migrations"
16	
17	type migrationConfig struct {
18		table string
19	}
20	
21	// MigrationOption customizes migration execution.
22	type MigrationOption func(*migrationConfig)
23	
24	// WithMigrationsTable stores migration records in a subsystem-specific table.
25	// Use this when independent migration streams share one SQLite database file.
26	func WithMigrationsTable(name string) MigrationOption {
27		return func(cfg *migrationConfig) {
28			if cfg == nil {
29				return
30			}
31			cfg.table = name
32		}
33	}
34	
35	// Migration describes one ordered SQLite schema change.
36	type Migration struct {
37		Version    int
38		Name       string
39		Statements []string
40		Up         func(ctx context.Context, tx *sql.Tx) error
41		Checksum   string
42	}
43	
44	// MigrationRecord describes one applied schema migration row.
45	type MigrationRecord struct {
46		Version   int
47		Name      string
48		Checksum  string
49		AppliedAt time.Time
50	}
51	
52	// EnsureSchema executes each schema statement in order.
53	func EnsureSchema(ctx context.Context, db *sql.DB, statements []string) error {
54		for _, stmt := range statements {
55			if _, err := db.ExecContext(ctx, stmt); err != nil {
56				return err
57			}
58		}
59		return nil
60	}
61	
62	// RunMigrations applies pending migrations once in deterministic version order.
63	func RunMigrations(ctx context.Context, db *sql.DB, migrations []Migration, opts ...MigrationOption) error {
64		if ctx == nil {
65			return errors.New("store: migrate schema context is required")
66		}
67		if db == nil {
68			return errors.New("store: migrate schema database is required")
69		}
70		cfg, err := newMigrationConfig(opts...)
71		if err != nil {
72			return err
73		}
74		ordered, err := normalizeMigrations(migrations)
75		if err != nil {
76			return err
77		}
78		if err := ensureSchemaMigrationsTable(ctx, db, cfg.table); err != nil {
79			return err
80		}
81	
82		applied, err := appliedMigrationRecords(ctx, db, cfg.table)
83		if err != nil {
84			return err
85		}
86		for _, migration := range ordered {
87			checksum, err := migrationChecksum(migration)
88			if err != nil {
89				return err
90			}
91			if record, ok := applied[migration.Version]; ok {
92				if record.Name != strings.TrimSpace(migration.Name) || record.Checksum != checksum {
93					return fmt.Errorf(
94						"store: migration %d integrity mismatch: recorded %q/%s, current %q/%s",
95						migration.Version,
96						record.Name,
97						record.Checksum,
98						strings.TrimSpace(migration.Name),
99						checksum,
100					)
